    "id": "payments_5.0.0_GET_pix_payments_paymentId_chunk_42_82f524d4",
    "text_content": "Do contrário, será coletada na detentora e trazida para a iniciadora como resposta à criação do pagamento.\\n\", \"required\": [ \"ispb\", \"number\", \"accountType\" ], \"properties\": { \"ispb\": { \"type\": \"string\", \"minLength\": 8, \"maxLength\": 8, \"pattern\": \"^[0-9A-Z]{8}$\", \"example\": \"123456BC\", \"description\": \"Deve ser preenchido com o ISPB (Identificador do Sistema de Pagamentos Brasileiros) do participante do SPI (Sistema de pagamentos instantâneos) somente com números.\\n\" }, \"issuer\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 4, \"pattern\": \"^[0-9]{1,4}$\", \"example\": \"1774\", \"description\": \"Código da Agência emissora da conta sem dígito. \\n(Agência é a dependência destinada ao atendimento aos clientes, ao público em geral e aos associados de cooperativas de crédito, \\nno exercício de atividades da instituição, não podendo ser móvel ou transitória).\\n\\n[Restrição] Preenchimento obrigatório para os seguintes tipos de conta: CACC (CONTA_DEPOSITO_A_VISTA) e SVGS (CONTA_POUPANCA).\\n\" }, \"number\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 20, \"pattern\": \"^[0-9]{1,20}$\", \"example\": \"1234567890\", \"description\": \"Deve ser preenchido com o número da conta transacional do usuário pagador, com dígito verificador (se este existir), \\nse houver valor alfanumérico, este deve ser convertido para 0.\\n\" }, \"accountType\": \"[Circular Reference]\" } }, \"authorisationFlow\": { \"type\": \"string\", \"enum\": [ \"HYBRID_FLOW\", \"CIBA_FLOW\", \"FIDO_FLOW\" ], \"example\": \"HYBRID_FLOW\", \"description\": \"Campo condicional utilizado para identificar o fluxo de autorização em que o pagamento foi solicitado.\\n\\n[Restrição] Se CIBA ou FIDO, preenchimento obrigatório. Caso o campo não esteja presente no payload, subentende-se que o fluxo de autorização utilizado é o HYBRID_FLOW.\\n\" } } }, \"links\": { \"type\": \"object\", \"description\": \"Referências para outros recusos da API requisitada.\", \"required\": [ \"self\" ], \"properties\": { \"self\": { \"type\": \"string\", \"format\": \"uri\", \"maxLength\": 2000, \"description\": \"URI completo que gerou a resposta atual.\", \"example\": \"https://api.banco.com.br/open-banking/api/v1/resource\", \"pattern\": \"^(https:\\\\/\\\\/)?(",
